privacyMutation.query:
#graphql
  mutation ShopPolicyUpdate($shopPolicy: ShopPolicyInput!) {
    shopPolicyUpdate(shopPolicy: $shopPolicy) {
      shopPolicy {

  id
  title
  body
  type
  url
  createdAt
  updatedAt

      }
      userErrors {
        field
        message
        code
      }
    }
  }

privacyNodeRead.query:
#graphql
  query ShopPolicyNodeRead($id: ID!) {
    node(id: $id) {
      __typename
      ... on ShopPolicy {
        id
        title
        body
        type
        url
        createdAt
        updatedAt
      }
    }
  }

